<script>
function sorError(m){$('.isi_warning_delete').text(m||<?=sd_js('sales_order_report_process_failed', 'Sales Order Report failed to process.');?>);$('.error_data_delete').fadeIn();}
function sorFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),customer:$('#filter_customer').val(),approval_status:$('#filter_approval_status').val(),status_so:$('#filter_status_so').val(),sales_person:$('#filter_sales_person').val(),currency:$('#filter_currency').val(),fulfillment_status:$('#filter_fulfillment_status').val(),keyword:$('#filter_keyword').val()};}
function sorQuery(){return $.param(sorFilters());}
$(function(){if($.fn.datepicker){$('.sor-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_customer,#filter_approval_status,#filter_status_so,#filter_sales_person,#filter_currency,#filter_fulfillment_status').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_sales_order_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=sd_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'78px',targets:1},{targets:[7,8,9,10],className:'text-right'}],ajax:{url:'<?=base_admin();?>modul/sales_order_report/sales_order_report_data.php',type:'post',data:function(d){$.extend(d,sorFilters());},error:function(xhr){console.log(xhr.responseText);sorError(<?=sd_js('sales_order_report_load_failed', 'Sales Order Report data failed to load.');?>);}}});
$('#btn_filter_sor').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_sor').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_customer,#filter_approval_status,#filter_status_so,#filter_sales_person,#filter_currency,#filter_fulfillment_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_sor').click(function(){window.location='<?=base_admin();?>modul/sales_order_report/sales_order_report_action.php?act=excel&'+sorQuery();});
$(document).on('click','.btn-sor-detail',function(){$.post('<?=base_admin();?>modul/sales_order_report/sales_order_report_action.php?act=detail',{id:$(this).data('id')},function(html){$('#sor_detail_body').html(html);$('#modal_detail_sor').modal('show');}).fail(function(){sorError('Detail gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
